def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
        else:
            ratio = item / capacity
            if ratio < 0.5:
                priorities[i] = (1 - ratio) ** 2 * 10
            elif 0.5 <= ratio <= 1:
                priorities[i] = np.log1p(ratio) * 5
            else:
                penalty = 0
                for j in range(1, int(ratio) + 1):
                    if ratio % j == 0:
                        penalty += j
                priorities[i] = penalty + (ratio - 1) * 20
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 100)
    return priorities
